import{_ as t,o as s,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt1703.jpg",i="/images/lekt1701.jpg",l="/images/lekt1702.jpg",g=JSON.parse('{"title":"Lektion 17","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion17.md","filePath":"lektionen/lektion17.md"}'),o={name:"lektionen/lektion17.md"};function u(p,e,d,h,b,m){return s(),r("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-17" tabindex="-1">Lektion 17 <a class="header-anchor" href="#lektion-17" aria-label="Permalink to &quot;Lektion 17&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>17.1. Zweite Präsensklasse (अदादि = अद् usw.)</li><li>17.2. Wurzeln der zweiten Präsensklasse mit Stammabstufung Hochstufe - Tiefstufe</li><li>17.3. Wurzeln der zweiten Präsensklasse mit Stammabstufung Dehnstufe - Tiefstufe</li><li>17.4. Wurzeln der zweiten Präsensklasse ohne Stammabstufung</li><li>17.5. Zweisilbige Wurzeln auf -i/-ī mit Stammabstufung</li><li>17.6. Wortliste</li><li>17.7. Übung 1</li><li>17.8. Übung 2</li></ul><h2 id="_17-1-zweite-prasensklasse-अदादि-अद्-usw" tabindex="-1">17.1. Zweite Präsensklasse (अदादि = अद् usw.) <a class="header-anchor" href="#_17-1-zweite-prasensklasse-अदादि-अद्-usw" aria-label="Permalink to &quot;17.1. Zweite Präsensklasse (अदादि = अद् usw.)&quot;">​</a></h2><p>Die Verbalendungen treten direkt an die Wurzel. Dabei sind die aus dem Wortsandhi resultierenden Lautveränderungen zu beachte.</p><p>Es gibt folgende Bildungsformen in der zweiten präsensklasse:</p><ol><li>Wurzeln mit Stammabstufung <ul><li>meistens: Hochstufe - Tiefstufe</li><li>einige Wurzeln: Dehnstufe - Tiefstufe</li></ul></li><li>Wurzeln ohne Stammabstufung</li><li>zweisilbige Wurzeln auf -i/-ī mit Stammabastufung</li></ol><h2 id="_17-2-wurzeln-der-zweiten-prasensklasse-mit-stammabstufung-hochstufe-tiefstufe" tabindex="-1">17.2. Wurzeln der zweiten Präsensklasse mit Stammabstufung Hochstufe - Tiefstufe <a class="header-anchor" href="#_17-2-wurzeln-der-zweiten-prasensklasse-mit-stammabstufung-hochstufe-tiefstufe" aria-label="Permalink to &quot;17.2. Wurzeln der zweiten Präsensklasse mit Stammabstufung Hochstufe - Tiefstufe&quot;">​</a></h2><p>Beispiele:</p><p>द्विष् 2 U &quot;hassen&quot;</p><ul><li>starker Präsensstamm: dveṣ-</li><li>schwacher Präsensstamm: dviṣ-</li></ul><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>द्वेष्टि (« dveṣ + -ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>द्विषन्ति (dviṣ-anti)</td></tr><tr><td>3. sg. Präs. Ā</td><td>द्विष्टे (« dviṣ + -te)</td></tr><tr><td>3. pl. Präs. Ā</td><td>द्विषते (dviṣ-ate)</td></tr></tbody></table></blockquote><p>Hierbei wirkt folgendes Wortsandhigesetz:</p><p>Wortsandhi von -ṣ + t(h)-</p><p>-ṣ + t(h)- » -ṣṭ(h)-</p><p>Weitere Beispiele:</p><p>इ 2 P &quot;gehen&quot; (Ā nach bestimmten Präverbien)</p><ul><li>starker Präsensstamm: e-</li><li>schwacher Präsensstamm: <ul><li>vor Konsonant: i-</li><li>vor Vokal: y-/iy-</li></ul></li></ul><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>एति (e-ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>यन्ति (y-anti)</td></tr><tr><td>3. sg. Präs. Ā</td><td>इते (i-te)</td></tr><tr><td>3. pl. Präs. Ā</td><td>इयते (iy-ate)</td></tr></tbody></table></blockquote><p>दुह् 2 U &quot;melken&quot;</p><ul><li>starker Präsensstamm: doh-</li><li>schwacher Präsensstamm: duh-</li></ul><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>दोग्धि (« doh- + -ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>दुहन्ति (duh-anti)</td></tr><tr><td>3. sg. Präs. Ā</td><td>दुग्धे (« duh- + -te)</td></tr><tr><td>3. pl. Präs. Ā</td><td>दुहते (duh-ate)</td></tr></tbody></table></blockquote><p>हन् 2 P &quot;schlagen, erschlagen, töten&quot;</p><ul><li>starker Präsensstamm: han-</li><li>schwacher Präsensstamm: <ul><li>vor Konsonant: ha- (« *hn-)</li><li>vor Vokal: ghn-/han-</li></ul></li></ul><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>हन्ति (han-ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>घ्नन्ति (ghn-anti)</td></tr><tr><td>3. sg. Präs. Ā</td><td>(हते) (ha-te)</td></tr><tr><td>3. pl. Präs. Ā</td><td>(घ्नते) (ghn-ate)</td></tr></tbody></table></blockquote><p>अस् 2 P &quot;sein&quot;</p><ul><li>starker Präsensstamm: as-</li><li>schwacher Präsensstamm: s-</li></ul><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>अस्ति  (as-ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>सन्ति (s-anti)</td></tr></tbody></table></blockquote><h2 id="_17-3-wurzeln-der-zweiten-prasensklasse-mit-stammabstufung-dehnstufe-tiefstufe" tabindex="-1">17.3. Wurzeln der zweiten Präsensklasse mit Stammabstufung Dehnstufe - Tiefstufe <a class="header-anchor" href="#_17-3-wurzeln-der-zweiten-prasensklasse-mit-stammabstufung-dehnstufe-tiefstufe" aria-label="Permalink to &quot;17.3. Wurzeln der zweiten Präsensklasse mit Stammabstufung Dehnstufe - Tiefstufe&quot;">​</a></h2><p>Beispiel:</p><p>स्तु 2 U &quot;preisen&quot;</p><ul><li>starker Präsensstamm: stau-</li><li>schwacher Präsesnsstamm: <ul><li>vor Konsonant: stu-</li><li>vor Vokal: stuv-</li></ul></li></ul><blockquote><p>| 3. sg. Präs. P | स्तौति (stau-ti) oder: स्तवीति siehe unter 5.</p><p>| | --- | --- | | 3. pl. Präs. P | स्तुवन्ति (stuv-anti) | | 3. sg. Präs. Ā | स्तुते (stu-te) | | 3. pl. Präs. Ā | स्तुवते (stuv-ate) |</p></blockquote><h2 id="_17-4-wurzeln-der-zweiten-prasensklasse-ohne-stammabstufung" tabindex="-1">17.4. Wurzeln der zweiten Präsensklasse ohne Stammabstufung <a class="header-anchor" href="#_17-4-wurzeln-der-zweiten-prasensklasse-ohne-stammabstufung" aria-label="Permalink to &quot;17.4. Wurzeln der zweiten Präsensklasse ohne Stammabstufung&quot;">​</a></h2><p>Ohne Stammabstufung sind Wurzeln der zweiten Präsensklasse auf -ā</p><p>Beispiel:</p><p>पा  2 P &quot;schützen, behüten, hüten&quot;</p><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>पाति (pā-ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>पान्ति (« pā- + -anti)</td></tr></tbody></table></blockquote><p>Auch einige andere Wurzeln der zweiten Klasse haben keine Stammabstufung:</p><p>Beispiele:</p><p>अद् 2 P &quot;essen&quot;</p><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>अत्ति (« ad- + -ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>अदन्ति (ad-anti)</td></tr></tbody></table></blockquote><p>आस् 2 Ā &quot;sitzen&quot;</p><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. Ā</th><th>आस्ते (ās-te)</th></tr></thead><tbody><tr><td>3. pl. Präs. Ā</td><td>आसते (ās-ate)</td></tr></tbody></table></blockquote><p>वच् 2 P &quot;sagen&quot;</p><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>वक्ति (« vac- + -ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>kommt nicht vor</td></tr></tbody></table></blockquote><h2 id="_17-5-zweisilbige-wurzeln-auf-i-i-mit-stammabstufung" tabindex="-1">17.5. Zweisilbige Wurzeln auf -i/-ī mit Stammabstufung <a class="header-anchor" href="#_17-5-zweisilbige-wurzeln-auf-i-i-mit-stammabstufung" aria-label="Permalink to &quot;17.5. Zweisilbige Wurzeln auf -i/-ī mit Stammabstufung&quot;">​</a></h2><p>Mehrere Wurzeln sind in einer Reihe von Formen zweisilbig, d.h. sie haben vor konsonantischer Endung ein -i (bzw. vor einigen Endungen -ī). Diese Wurzeln werden aber trotzdem von den einheimischen Grammatikern und in Wörterbüchern usw. als einsilbig angesetzt.</p><p>Beispiele:</p><p>रुद् 2 P &quot;weinen, heulen&quot;</p><ul><li>starker Präsensstamm: rodi-</li><li>schwacher Präsensstamm: <ul><li>vor Konsonant: rudi-</li><li>vor Vokal: rud-</li></ul></li></ul><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>रोदिति (rodi-ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>रुदन्ति (rud-anti)</td></tr></tbody></table></blockquote><p>ब्रू 2 U &quot;sprechen&quot;</p><ul><li>starker Präsensstamm: bravī- (« bro- + -ī)</li><li>schwacher Präsensstamm: <ul><li>vor Konsonant: brū-</li><li>vor Vokal: bruv-</li></ul></li></ul><blockquote><table tabindex="0"><thead><tr><th>3. sg. Präs. P</th><th>ब्रवीति (bravī-ti)</th></tr></thead><tbody><tr><td>3. pl. Präs. P</td><td>ब्रुवन्ति (bruv-anti)</td></tr><tr><td>3. sg. Präs. Ā</td><td>ब्रूते (brū-te)</td></tr><tr><td></td><td></td></tr><tr><td>3. pl. Präs. Ā</td><td></td></tr></tbody></table><p>| ब्रुवते (bruv-ate) |</p></blockquote><p>Auch स्तु 2 U &quot;preisen&quot; hat neben den unter 3. angegebenen Formen Formen nach diesem Muster:</p><blockquote><p>| 3. sg. Präs. P | स्तवीति (« sto + ī + ti) oder: स्तौति siehe unter 3.</p><p>| | --- | --- |</p></blockquote><h2 id="_17-6-wortliste" tabindex="-1">17.6. Wortliste <a class="header-anchor" href="#_17-6-wortliste" aria-label="Permalink to &quot;17.6. Wortliste&quot;">​</a></h2><p>हन् 2 P हन्ति, घ्नन्ति Pass. हन्यते  PPP हत : schlagen, erschlagen, töten</p><p>davon:</p><blockquote><p>घात m.: Tötung</p></blockquote><p><img src="'+n+'" alt=""><br> Abb.: घाताः<br> Bangalore = ಬೆಂಗಳೂರು<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/143399263/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/143399263/</a>. -- Zugriff am 2008-12-07. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>आस् 2Ā आस्ते Pass. आस्यते PPP आसित : sitzen</p><p>davon:</p><blockquote><p>आसन n.: das Sitzen, Sitz ; auch: Sitzpositionen des Yogin</p></blockquote><p><img src="'+i+'" alt=""><br> Abb.: योगासनम्<br> [Bildquelle: von tlongacre. -- <a href="http://www.flickr.com/photos/tlongacre/2177187487/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/tlongacre/2177187487/</a>. -- Zugriff am 2008-12-07. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine Bearbeitung)]</p><p>रुद् 2 P रोदिति Pass. रुद्यते PPP रुदित : weinen, heulen</p><p>davon:</p><blockquote><p>रुद्र m.: (der Heuler =) der Sturmgott Rudra</p></blockquote><p>ब्रू 2 U ब्रवीति Ā ब्रुते kein Passiv und PPP: sprechen, sagen (etwas zu jemandem: doppelter Akkusativ)</p><p>दुह् 2 U दोग्धि Pass. दुह्यते PPP दुग्ध : melken</p><p><img src="'+l+'" alt=""><br> Abb.: दोग्धि<br> [Bildquelle: Roshnii. -- <a href="http://www.flickr.com/photos/roshnii/110086482/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/roshnii/110086482/</a>. -- Zugriff am 2008-12-07.  -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>दिश् 6 U दिशति Pass. दिश्यते PPP दिष्ट : zeigen, anweisen, befehlen</p><p>davon:</p><blockquote><p>दिष्टि f.: Anweisung, glückliche Fügung</p><p>दिष्ट्या Instr.: (wörtl.: durch eine glückliche Fügung) O glückliche Fügung (Ausruf der Freude und Beglückung)</p></blockquote><h2 id="ubung-1" tabindex="-1">Übung 1 <a class="header-anchor" href="#ubung-1" aria-label="Permalink to &quot;Übung 1&quot;">​</a></h2><p>A) Setzen Sie in folgenden Sätzen das Verb ein und übersetzen Sie:</p><p>१. ब्राह्मनो ऽनृतं न ... (ब्रू । वच् । वद्)</p><p>२. क्षत्रियो जनान् ... (पा । रक्ष्)</p><p>३. बलवद्योधो द्विजारीन् ... (जि । हन् । युध्)</p><p>४. ब्राह्मणकविर्लोकेश्वरम् ... (स्तु । यज्)</p><p>५. अग्निर्यज्ञान्नम् ... (अद् । दह्)</p><p>६. बालवैश्यो धेनुम् ... (दुह् । रक्ष् । पा)</p><p>७. द्विजदासो मृगमार्गेण ब्राह्मणग्रामम् ... (गम् । इ । पद्)</p><p>८. द्विजदासः शूद्रस् ... (अस् २ । भू)</p><p>९. बालब्राह्मणी ... (रुद् । आस् । मृ)</p><p>१०. साधुजनो ऽधर्मम् ... (द्विष् । न कृ)</p><p>B) Setzen Sie in den in A) gebildeten Sätzen Agens und Verb in den Plural</p><h2 id="ubung-2" tabindex="-1">Übung 2 <a class="header-anchor" href="#ubung-2" aria-label="Permalink to &quot;Übung 2&quot;">​</a></h2><p>Übersetzen Sie folgende Verbformen und geben Sie die dazugehörige Wurzel an:</p><p>१. अदन्ति</p><p>२. सन्ति</p><p>३. आसते</p><p>४. यन्ति</p><p>५. इच्छति</p><p>६. कुर्वते</p><p>७. गच्छन्ति</p><p>८. जायते</p><p>९. जयति</p><p>१०. तनोति</p><p>११. दहति</p><p>१२. दोग्धि</p><p>१३. पश्यति</p><p>१४. द्विष्टे</p><p>१५. नयन्ति</p><p>१६. नृत्यति</p><p>१७. पद्यन्ते</p><p>१८. पिबति</p><p>१९. पान्ति</p><p>२०. पृच्छति</p><p>२१. बुध्यन्ते</p><p>२२. ब्रवीति</p><p>२३. भवन्ति</p><p>२४. मन्यते</p><p>२५. मुञ्चन्ति</p><p>२६. म्रियन्ते</p><p>२७. यजते</p><p>२८. युध्यन्ते</p><p>२९. रक्षति</p><p>३०. रोदिति</p><p>३१. लभते</p><p>३२. वक्ति</p><p>३३. वदति</p><p>३४. शृणोति</p><p>३५. स्तौति</p><p>३६. स्मरति</p><p>३७. हन्ति</p><p>३८. अश्नुवते</p><p>३९. कुप्यते</p><p>४० कर्षन्ति</p><p>४१. उद्यते</p><p>४२. सहन्ते</p><p>४३. सिच्यन्ते</p><p>४४. आप्नोति</p><p>४५. जीव्यते</p><p>४६. दिश्यन्ते</p>',137)])])}const P=t(o,[["render",u]]);export{g as __pageData,P as default};
